// CSS 文本与 React 挂载点都落 shadow 容器;把主题变量的 :root 作用域改到 :host
import React from 'https://cdn.jsdelivr.net/npm/react@19.2.3/+esm';
import { createRoot } from 'https://cdn.jsdelivr.net/npm/react-dom@19.2.3/client/+esm';
import { Chrono } from 'https://cdn.jsdelivr.net/npm/react-chrono@3/+esm';
const raw = await fetch('https://cdn.jsdelivr.net/npm/react-chrono@3/dist/style.css').then(r => r.text());
const style = document.createElement('style'); style.textContent = raw.replaceAll(':root', ':host');
const el = document.createElement('div'); el.style.height = `${spec.height ?? 480}px`; shadowRoot.append(style, el);
createRoot(el).render(React.createElement(Chrono, { items: data.items, mode: data.mode ?? 'vertical', layout: { timelineHeight: spec.height ?? 480 } }));

